<div class="card-dark"><h5><?= $item?'Editar':'Nuevo' ?> cable</h5><form method="post" enctype="multipart/form-data" action="<?= url('cables/guardar') ?>" class="row g-2"><?= csrf_field() ?><input type="hidden" name="id" value="<?= e($item['id']??'') ?>"><div class="col-md-3"><label>Número</label><input required class="form-control" name="numero_cable" value="<?= e($item['numero_cable']??'') ?>"></div><div class="col-md-3"><label>Marca</label><select class="form-select" name="marca_id"><?php foreach($marcas as $m): ?><option value="<?= $m['id'] ?>" <?= ($item['marca_id']??'')==$m['id']?'selected':'' ?>><?= e($m['nombre']) ?></option><?php endforeach; ?></select></div><div class="col-md-3"><label>Calibre/Sección</label><input class="form-control" name="calibre" value="<?= e($item['calibre']??'') ?>"></div><div class="col-md-3"><label>Tipo enchufe</label><input class="form-control" name="tipo_enchufe" value="<?= e($item['tipo_enchufe']??'') ?>"></div><div class="col-md-3"><label>Aislación</label><input class="form-control" name="aislacion" value="<?= e($item['aislacion']??'') ?>"></div><div class="col-md-2"><label>Largo</label><input type="number" step="0.01" class="form-control" name="largo" value="<?= e($item['largo']??'') ?>"></div><div class="col-md-3"><label>Capacidad aislación</label><input class="form-control" name="capacidad_aislacion" value="<?= e($item['capacidad_aislacion']??'') ?>"></div><div class="col-md-2"><label>Estado</label><select class="form-select" name="estado"><?php foreach(['disponible','en reparación','entregado','dado de baja'] as $e): ?><option <?= ($item['estado']??'')===$e?'selected':'' ?>><?= $e ?></option><?php endforeach; ?></select></div><div class="col-md-2"><label>Imagen</label><input type="file" name="imagen" class="form-control"></div><div class="col-12"><label>Observación</label><textarea name="observacion" class="form-control"><?= e($item['observacion']??'') ?></textarea></div><div><button class="btn btn-seim">Guardar</button></div></form></div>
